107	function cachedPhotoFromPhoto(photo: PhotoItem): CachedChinaPhoto {
108	  return {
109	    id: photo.id,
110	    trip_id: photo.trip_id,
111	    file_path: photo.file_path,
112	    thumbnail_path: photo.thumbnail_path,
113	    media_type: photo.media_type ?? null,
114	    product_name: photo.product_name,
115	    category: photo.category ?? null,
116	    price: photo.price ?? null,
117	    dimensions: photo.dimensions ?? null,
118	    country_of_origin: photo.country_of_origin ?? null,
119	    material: photo.material ?? null,
120	    brand: photo.brand ?? null,
121	    notes: photo.notes ?? null,
122	    section: photo.section ?? null,
123	    image_type: photo.image_type ?? null,
124	    group_id: photo.group_id ?? null,
125	    user_id: photo.user_id ?? null,
126	    created_at: photo.created_at || new Date().toISOString(),
127	  };
128	}
129	
130	function getColumnCount(width: number) {
131	  if (width >= 1280) return 8;
132	  if (width >= 1024) return 6;
133	  if (width >= 640) return 4;
134	  return 3;
135	}
136	
137	function useContainerWidth() {
138	  const ref = useRef<HTMLDivElement>(null);
139	  const [width, setWidth] = useState(0);
140	
141	  useEffect(() => {
142	    const node = ref.current;
143	    if (!node) return;
144	
145	    const update = () => setWidth(node.clientWidth);
146	    update();
147	
148	    if (!("ResizeObserver" in window)) {
149	      window.addEventListener("resize", update);
150	      return () => window.removeEventListener("resize", update);
151	    }
152	
153	    const observer = new ResizeObserver(update);
154	    observer.observe(node);
155	    return () => observer.disconnect();
156	  }, []);
157	
158	  return { ref, width };
159	}
160	
161	function useCachedBlobUrl(filePath: string, signedUrl: string | undefined, online: boolean) {
162	  const [blobUrl, setBlobUrl] = useState(() => blobUrlCache.get(filePath));
163	  const [src, setSrc] = useState(() => blobUrlCache.get(filePath) || (online ? signedUrl : undefined));
164	
165	  useEffect(() => {
166	    let cancelled = false;
167	    const cached = blobUrlCache.get(filePath);
168	    if (cached) {
169	      setBlobUrl(cached);
170	      setSrc(cached);
171	      return;
172	    }
173	
174	    setBlobUrl(undefined);
175	    setSrc(online ? signedUrl : undefined);
176	    if (blobMissCache.has(filePath)) return;
177	
178	    getCachedImageBlob(filePath).then((blob) => {
179	      if (cancelled) return;
180	      if (blob && (blob.type.startsWith("image/") || blob.type.startsWith("video/"))) {
181	        const url = URL.createObjectURL(blob);
182	        blobUrlCache.set(filePath, url);
183	        setBlobUrl(url);
184	        setSrc(url);
185	      } else {
186	        blobMissCache.add(filePath);
187	      }
188	    }).catch(() => blobMissCache.add(filePath));
189	
190	    return () => { cancelled = true; };
191	  }, [filePath, online, signedUrl]);
192	
193	  return { src, cached: Boolean(blobUrl) };
194	}
195	
196	function StreamThumb({ photo, online, priority }: { photo: PhotoItem; online: boolean; priority: boolean }) {
197	  const { src, cached } = useCachedBlobUrl(photo.display_path, photo.display_url, online);
198	  const isVideo = photo.media_type === "video";
199	
200	  return (
201	    <button
202	      type="button"
203	      className="group relative aspect-square overflow-hidden rounded-md bg-muted text-left focus:outline-none focus:ring-2 focus:ring-primary"
204	      aria-label={photo.product_name ?? (isVideo ? "Video" : "Photo")}
205	    >
206	      {src ? (
207	        <img
208	          src={src}
209	          alt={photo.product_name ?? (isVideo ? "Video" : "Photo")}
210	          className="h-full w-full object-cover"
211	          loading={priority || cached ? "eager" : "lazy"}
212	          decoding="async"
213	          draggable={false}
214	        />
215	      ) : (
216	        <div className="flex h-full w-full items-center justify-center bg-muted">
217	          {isVideo ? <Video className="h-6 w-6 text-muted-foreground/40" /> : <Factory className="h-6 w-6 text-muted-foreground/30" />}
218	        </div>
219	      )}
220	      {isVideo && (
221	        <div className="absolute inset-0 flex items-center justify-center">
222	          <div className="rounded-full bg-black/60 p-2 backdrop-blur-sm">
223	            <Play className="h-4 w-4 fill-white text-white" />
224	          </div>
225	        </div>
226	      )}
227	      {photo.product_name && (
228	        <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/60 to-transparent px-1.5 pb-1 pt-5">
229	          <p className="truncate text-[10px] leading-tight text-white">{photo.product_name}</p>
230	        </div>
231	      )}
232	    </button>
233	  );
234	}
