236	export default function FairTripStreamV2() {
237	  const { id } = useParams<{ id: string }>();
238	  const navigate = useNavigate();
239	  const { user } = useAuth();
240	  const online = useOnlineStatus();
241	  const { ref: streamRef, width } = useContainerWidth();
242	
243	  const [fair, setFair] = useState<CachedChinaTrip | null>(null);
244	  const [sections, setSections] = useState<BoothSection[]>([]);
245	  const [loading, setLoading] = useState(true);
246	  const [loadedFromCache, setLoadedFromCache] = useState(false);
247	  const [cacheProgress, setCacheProgress] = useState<CacheProgress | null>(null);
248	  const [cacheStatus, setCacheStatus] = useState<string | null>(null);
249	
250	  const loadCachedStream = useCallback(async (): Promise<boolean> => {
251	    if (!id) return false;
252	    const cachedFair = await getCachedChinaTrip(id);
253	    const cachedTrips = await getCachedChinaTrips();
254	    const children = cachedTrips
255	      .filter((trip) => trip.parent_id === id && !trip.deleted_at)
256	      .sort((a, b) => a.date.localeCompare(b.date));
257	
258	    if (!cachedFair && children.length === 0) return false;
259	
260	    const cachedSections: BoothSection[] = [];
261	    for (const trip of children) {
262	      const photos = (await getCachedChinaPhotos(trip.id))
263	        .map(photoFromRow)
264	        .sort((a, b) => a.created_at.localeCompare(b.created_at));
265	      if (photos.length > 0) cachedSections.push({ trip, photos });
266	    }
267	
268	    setFair(cachedFair ?? null);
269	    setSections(cachedSections);
270	    setLoadedFromCache(true);
271	    return true;
272	  }, [id]);
273	
274	  const loadOnlineStream = useCallback(async () => {
275	    if (!id) return;
276	
277	    const { data: fairData } = await supabase
278	      .from("china_trips")
279	      .select("id, name, supplier, venue_type, date, end_date, location, notes, parent_id, factory_id, created_by, created_at, updated_at, deleted_at, is_draft")
280	      .eq("id", id)
281	      .single();
282	
283	    const { data: childRows } = await supabase
284	      .from("china_trips")
285	      .select("id, name, supplier, venue_type, date, end_date, location, notes, parent_id, factory_id, created_by, created_at, updated_at, deleted_at, is_draft")
286	      .eq("parent_id", id)
287	      .is("deleted_at", null)
288	      .order("date", { ascending: true });
289	
290	    const childTrips = (childRows ?? []).map(chinaTripFromRow);
291	    const childIds = childTrips.map((trip) => trip.id);
292	    const allPhotos: PhotoItem[] = [];
293	
294	    for (let i = 0; i < childIds.length; i += 10) {
295	      const chunk = childIds.slice(i, i + 10);
296	      const { data } = await supabase
297	        .from("china_photos")
298	        .select("id, trip_id, file_path, thumbnail_path, product_name, media_type, category, price, dimensions, country_of_origin, material, brand, notes, section, image_type, group_id, user_id, created_at")
299	        .in("trip_id", chunk)
300	        .order("created_at", { ascending: true });
301	      if (data) allPhotos.push(...data.map(photoFromRow));
302	    }
303	
304	    const urlMap = await batchSignedUrls(allPhotos.map((photo) => ({ file_path: photo.display_path })));
305	    const photosWithUrls = allPhotos.map((photo) => ({ ...photo, display_url: urlMap.get(photo.display_path) }));
306	
307	    const photosByTrip = new Map<string, PhotoItem[]>();
308	    for (const photo of photosWithUrls) {
309	      const list = photosByTrip.get(photo.trip_id) ?? [];
310	      list.push(photo);
311	      photosByTrip.set(photo.trip_id, list);
312	    }
313	
314	    const nextSections = childTrips
315	      .map((trip) => ({ trip, photos: photosByTrip.get(trip.id) ?? [] }))
316	      .filter((section) => section.photos.length > 0);
317	
318	    const nextFair = fairData ? chinaTripFromRow(fairData) : null;
319	    setFair(nextFair);
320	    setSections(nextSections);
321	    setLoadedFromCache(false);
322	
323	    const tripsToCache = nextFair ? [nextFair, ...childTrips] : childTrips;
324	    cacheChinaTrips(tripsToCache).catch(() => {});
325	    cacheChinaPhotos(photosWithUrls.map(cachedPhotoFromPhoto)).catch(() => {});
326	  }, [id]);
327	
328	  useEffect(() => {
329	    let cancelled = false;
330	    if (!user || !id) return;
331	
332	    (async () => {
333	      setLoading(true);
334	      const hadCachedData = await loadCachedStream();
335	      if (!cancelled && hadCachedData) setLoading(false);
336	
337	      if (!online) {
338	        if (!cancelled) setLoading(false);
339	        return;
340	      }
341	
342	      try {
343	        await loadOnlineStream();
344	      } finally {
345	        if (!cancelled) setLoading(false);
346	      }
347	    })();
348	
349	    return () => { cancelled = true; };
350	  }, [user, id, online, loadCachedStream, loadOnlineStream]);
351	
352	  const { columns, cellSize } = useMemo(() => {
353	    const columnCount = getColumnCount(window.innerWidth);
354	    const measuredWidth = width || 360;
355	    const size = Math.max(72, Math.floor((measuredWidth - GAP * (columnCount - 1)) / columnCount));
356	    return { columns: columnCount, cellSize: size };
357	  }, [width]);
358	
359	  const totalPhotos = sections.reduce((sum, section) => sum + section.photos.length, 0);
360	  const firstPriorityIds = new Set(sections.flatMap((section) => section.photos).slice(0, columns * 3).map((photo) => photo.id));
361	
362	  async function handleCacheFair() {
363	    if (!online) {
364	      setCacheStatus("Connect to the internet to cache this fair.");
365	      return;
366	    }
367	
368	    const photos = sections.flatMap((section) => section.photos);
369	    setCacheStatus(null);
370	    setCacheProgress({ total: photos.length, done: 0, failed: 0 });
371	
372	    const urlMap = await batchSignedUrls(photos.map((photo) => ({ file_path: photo.display_path })));
373	    const queue = photos.map((photo) => ({ ...photo, display_url: photo.display_url || urlMap.get(photo.display_path) }));
374	    const progress: CacheProgress = { total: queue.length, done: 0, failed: 0 };
375	    let index = 0;
376	
377	    async function worker() {
378	      while (index < queue.length) {
379	        const photo = queue[index++];
380	        try {
381	          const existing = await getCachedImageBlob(photo.display_path);
382	          if (existing && (existing.type.startsWith("image/") || existing.type.startsWith("video/"))) {
383	            if (!blobUrlCache.has(photo.display_path)) blobUrlCache.set(photo.display_path, URL.createObjectURL(existing));
384	          } else if (photo.display_url) {
385	            const res = await fetch(photo.display_url);
386	            if (!res.ok) throw new Error("Failed to download thumbnail");
387	            const blob = await res.blob();
388	            if (!blob.type.startsWith("image/") && !blob.type.startsWith("video/")) throw new Error("Invalid image blob");
389	            await cacheImageBlob(photo.display_path, blob);
390	            blobMissCache.delete(photo.display_path);
391	            if (!blobUrlCache.has(photo.display_path)) blobUrlCache.set(photo.display_path, URL.createObjectURL(blob));
392	          } else {
393	            progress.failed++;
394	          }
395	        } catch {
396	          progress.failed++;
397	        }
398	        progress.done++;
399	        setCacheProgress({ ...progress });
400	      }
401	    }
402	
403	    await Promise.all(Array.from({ length: Math.min(4, queue.length) }, () => worker()));
404	    setCacheProgress({ ...progress });
405	    setCacheStatus(progress.failed ? `${progress.failed} thumbnail${progress.failed === 1 ? "" : "s"} failed to cache.` : "Fair thumbnails cached for offline browsing.");
406	  }
407	
408	  return (
409	    <div className="container py-6">
410	      <div className="mb-4 flex flex-wrap items-center justify-between gap-3">
411	        <button
412	          onClick={() => navigate("/china")}
413	          className="flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground"
414	        >
415	          <ArrowLeft className="h-4 w-4" /> Back to Asia Trips
416	        </button>
417	        <button
418	          onClick={handleCacheFair}
419	          disabled={Boolean(cacheProgress && cacheProgress.done < cacheProgress.total)}
420	          className="inline-flex h-9 items-center gap-2 rounded-md border px-3 text-sm font-medium hover:bg-muted disabled:cursor-not-allowed disabled:opacity-60"
421	        >
422	          {cacheProgress && cacheProgress.done < cacheProgress.total ? <Loader2 className="h-4 w-4 animate-spin" /> : <Download className="h-4 w-4" />}
423	          Cache fair
424	        </button>
425	      </div>
426	
427	      <div className="mb-6">
428	        <div className="flex flex-wrap items-end justify-between gap-3">
429	          <div>
430	            <h1 className="font-sans text-2xl font-semibold md:text-3xl">{fair?.name ?? "Fair Trip"}</h1>
431	            {fair && (
432	              <p className="mt-1 flex flex-wrap items-center gap-x-3 gap-y-1 text-sm text-muted-foreground">
433	                <span className="flex items-center gap-1">
434	                  <Calendar className="h-3.5 w-3.5" />
435	                  {format(new Date(fair.date), "MMM d")}
436	                  {fair.end_date && ` - ${format(new Date(fair.end_date), "MMM d, yyyy")}`}
437	                </span>
438	                {fair.location && (
439	                  <span className="flex items-center gap-1"><MapPin className="h-3.5 w-3.5" /> {fair.location}</span>
440	                )}
441	              </p>
442	            )}
443	            {!loading && (
444	              <p className="mt-0.5 text-sm text-muted-foreground">
445	                {sections.length} booth{sections.length !== 1 ? "s" : ""} · {totalPhotos} photo{totalPhotos !== 1 ? "s" : ""}
446	                {loadedFromCache && " · cached data"}
447	                {!online && " · offline"}
448	              </p>
449	            )}
450	          </div>
451	          <button
452	            onClick={() => navigate(`/china/${id}/stream`)}
453	            className="text-sm font-medium text-primary hover:underline"
454	          >
455	            Open original view
456	          </button>
457	        </div>
458	        {cacheProgress && (
459	          <div className="mt-3 max-w-sm">
460	            <div className="h-2 overflow-hidden rounded-full bg-muted">
461	              <div
462	                className="h-full bg-primary transition-all"
463	                style={{ width: `${cacheProgress.total ? Math.round((cacheProgress.done / cacheProgress.total) * 100) : 0}%` }}
464	              />
465	            </div>
466	            <p className="mt-1 text-xs text-muted-foreground">
467	              {cacheProgress.done} / {cacheProgress.total} cached{cacheProgress.failed ? ` · ${cacheProgress.failed} failed` : ""}
468	            </p>
469	          </div>
470	        )}
471	        {cacheStatus && <p className="mt-2 text-sm text-muted-foreground">{cacheStatus}</p>}
472	      </div>
473	
474	      {loading && sections.length === 0 ? (
475	        <div className="space-y-8">
476	          {[1, 2, 3].map((i) => (
477	            <div key={i}>
478	              <div className="mb-3 h-5 w-48 animate-pulse rounded bg-muted" />
479	              <div className="grid grid-cols-3 gap-1.5 sm:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8">
480	                {Array.from({ length: 8 }).map((_, j) => <div key={j} className="aspect-square animate-pulse rounded-md bg-muted" />)}
481	              </div>
482	            </div>
483	          ))}
484	        </div>
485	      ) : sections.length === 0 ? (
486	        <div className="py-16 text-center text-sm text-muted-foreground">No photos found in this fair trip.</div>
487	      ) : (
488	        <div ref={streamRef} className="space-y-8">
489	          {sections.map((section, sectionIndex) => (
490	            <div key={section.trip.id}>
491	              {sectionIndex > 0 && <div className="mb-6 border-t" />}
492	              <button
493	                onClick={() => navigate(`/china/${section.trip.id}`)}
494	                className="mb-3 flex flex-wrap items-center gap-x-2 gap-y-0.5 text-left group"
495	              >
496	                <h2 className="font-sans text-base font-semibold transition-colors group-hover:text-primary">
497	                  {section.trip.supplier || section.trip.name}
498	                </h2>
499	                <span className="text-xs text-muted-foreground">
500	                  {format(new Date(section.trip.date), "MMM d")} · {section.photos.length} photo{section.photos.length !== 1 ? "s" : ""}
501	                </span>
502	              </button>
503	              <div
504	                className="grid gap-1.5"
505	                style={{
506	                  gridTemplateColumns: `repeat(${columns}, minmax(0, 1fr))`,
507	                  gridAutoRows: cellSize,
508	                }}
509	                onClick={() => navigate(`/china/${section.trip.id}`)}
510	              >
511	                {section.photos.map((photo) => (
512	                  <StreamThumb key={photo.id} photo={photo} online={online} priority={firstPriorityIds.has(photo.id)} />
513	                ))}
514	              </div>
515	            </div>
516	          ))}
517	        </div>
518	      )}
519	    </div>
520	  );
521	}
