1	import { useState, useEffect, useCallback } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { getCachedImageBlob, cacheImageBlob, getCachedSignedUrl, cacheSignedUrls } from "@/lib/offline-db";
4	
5	interface CachedImageProps extends React.ImgHTMLAttributes<HTMLImageElement> {
6	  filePath: string;
7	  signedUrl?: string;
8	  /** Fallback content when no image is available */
9	  fallback?: React.ReactNode;
10	}
11	
12	// Module-level cache: filePath → blob URL created from IndexedDB blob.
13	// Keeps the URL alive across component unmounts so remounting the same image
14	// is instant (no IndexedDB round-trip, no fallback flash).
15	const memBlobUrlCache = new Map<string, string>();
16	const blobCacheWrites = new Map<string, Promise<void>>();
17	const SIGNED_URL_TTL = 86400;
18	const SIGNED_URL_TTL_MS = SIGNED_URL_TTL * 1000;
19	
20	function cacheImageFromUrl(filePath: string, url: string) {
21	  if (blobCacheWrites.has(filePath)) return blobCacheWrites.get(filePath)!;
22	
23	  const write = (async () => {
24	    try {
25	      const existing = await getCachedImageBlob(filePath);
26	      if (existing && (existing.type.startsWith("image/") || existing.type.startsWith("video/"))) return;
27	      const res = await fetch(url);
28	      if (!res.ok) return;
29	      const blob = await res.blob();
30	      if (!blob.type.startsWith("image/") && !blob.type.startsWith("video/")) return;
31	      await cacheImageBlob(filePath, blob);
32	      if (!memBlobUrlCache.has(filePath)) {
33	        memBlobUrlCache.set(filePath, URL.createObjectURL(blob));
34	      }
35	    } catch {
36	      // Background cache writes must never disrupt the visible image.
37	    } finally {
38	      blobCacheWrites.delete(filePath);
39	    }
40	  })();
41	
42	  blobCacheWrites.set(filePath, write);
43	  return write;
44	}
45	
46	/**
47	 * An <img> that checks IndexedDB blob cache first, then falls back to the
48	 * signed URL directly (letting the browser handle loading). After the image
49	 * loads successfully from a URL, the blob is cached in the background for
50	 * offline use — no eager fetch on mount to avoid thundering-herd blinking.
51	 */
52	export default function CachedImage({ filePath, signedUrl, fallback, ...imgProps }: CachedImageProps) {
53	  const [src, setSrc] = useState<string | undefined>(() => memBlobUrlCache.get(filePath) ?? signedUrl);
54	  const [blobUrl, setBlobUrl] = useState<string | undefined>(() => memBlobUrlCache.get(filePath));
55	  const [failed, setFailed] = useState(false);
56	
57	  useEffect(() => {
58	    setFailed(false);
59	
60	    // Already have a blob URL in memory for this path — nothing to do.
61	    if (memBlobUrlCache.has(filePath)) {
62	      const cached = memBlobUrlCache.get(filePath)!;
63	      setSrc(cached);
64	      setBlobUrl(cached);
65	      return;
66	    }
67	
68	    setBlobUrl(undefined);
69	    if (signedUrl) {
70	      setSrc(signedUrl);
71	    } else {
72	      setSrc(undefined);
73	    }
74	
75	    let cancelled = false;
76	
77	    (async () => {
78	      // 1. Check blob cache (skip corrupted non-image entries)
79	      const blob = await getCachedImageBlob(filePath);
80	      if (cancelled) return;
81	      if (blob && (blob.type.startsWith("image/") || blob.type.startsWith("video/"))) {
82	        const url = URL.createObjectURL(blob);
83	        memBlobUrlCache.set(filePath, url);
84	        setBlobUrl(url);
85	        if (!signedUrl) setSrc(url);
86	        return;
87	      }
88	
89	      // 2. Resolve the best URL: prop > IndexedDB signed URL cache
90	      let resolvedUrl = signedUrl;
91	      if (!resolvedUrl) {
92	        const cached = await getCachedSignedUrl(filePath);
93	        if (cached && cached.expires_at > Date.now()) {
94	          resolvedUrl = cached.url;
95	        }
96	      }
97	
98	      if (!resolvedUrl) {
99	        const { data } = await supabase.storage.from("photos").createSignedUrl(filePath, SIGNED_URL_TTL);
100	        if (data?.signedUrl) {
101	          resolvedUrl = data.signedUrl;
102	          cacheSignedUrls([{
103	            file_path: filePath,
104	            url: data.signedUrl,
105	            expires_at: Date.now() + SIGNED_URL_TTL_MS,
106	          }]).catch(() => {});
107	        }
108	      }
109	
110	      // 3. Set src directly — let the browser/img tag handle fetching.
111	      //    Blob caching happens lazily in onLoad to avoid thundering-herd fetches.
112	      if (resolvedUrl && !cancelled) {
113	        setSrc(resolvedUrl);
114	      } else if (!cancelled) {
115	        setSrc(undefined);
116	      }
117	    })();
118	
119	    return () => {
120	      cancelled = true;
121	      // Don't revoke blob URLs — memBlobUrlCache keeps them alive for instant remounts.
122	    };
123	  }, [filePath, signedUrl]);
124	
