      type="button"
      className="group relative aspect-square overflow-hidden rounded-md bg-muted text-left focus:outline-none focus:ring-2 focus:ring-primary"
      aria-label={photo.product_name ?? (isVideo ? "Video" : "Photo")}
    >
      {src ? (
        <img
