  }

  if (!src) {
    return <>{fallback ?? <div className={imgProps.className + " bg-muted"} />}</>;
  }

  return (
    <img
      {...imgProps}
      src={src}
      onLoad={handleLoad}
      onError={() => {
        setFailed(true);
        setSrc(undefined);
      }}
    />
  );
